@implements IAsyncDisposable
@inject IJSRuntime JS

@ChildContent

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public int TimeoutSeconds { get; set; } = 300;
    [Parameter] public EventCallback OnIdle { get; set; }
    [Parameter] public EventCallback OnActive { get; set; }

    private IJSObjectReference? _module;
    private DotNetObjectReference<UserActivityTracker>? _dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv-54ed29549d304f24b7adf2d56d250d9a/Components/UserActivityTracker.razor.js");
            await _module.InvokeVoidAsync("initialize", _dotNetRef, TimeoutSeconds);
        }
    }

    [JSInvokable]
    public async Task OnIdleCallback() => await OnIdle.InvokeAsync();

    [JSInvokable]
    public async Task OnActiveCallback() => await OnActive.InvokeAsync();

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            try
            {
                await _module.InvokeVoidAsync("dispose");
                await _module.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }
        _dotNetRef?.Dispose();
    }
}

let dotNetRef = null;
let timeoutId = null;
let isIdle = false;
let timeoutMs = 0;

const events = ["mousemove", "keydown", "click", "scroll", "touchstart"];

function onActivity() {
    if (isIdle) {
        isIdle = false;
        dotNetRef.invokeMethodAsync("OnActiveCallback");
    }
    resetTimer();
}

function resetTimer() {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => {
        isIdle = true;
        dotNetRef.invokeMethodAsync("OnIdleCallback");
    }, timeoutMs);
}

export function initialize(ref, timeoutSeconds) {
    dotNetRef = ref;
    timeoutMs = timeoutSeconds * 1000;
    isIdle = false;

    for (const evt of events) {
        document.addEventListener(evt, onActivity, { passive: true });
    }

    resetTimer();
}

export function dispose() {
    clearTimeout(timeoutId);
    timeoutId = null;

    for (const evt of events) {
        document.removeEventListener(evt, onActivity);
    }

    dotNetRef = null;
}

